### Step 1: `packages/shared/src/theme.ts` — Create new file

This is a pure TypeScript file with no imports, no dependencies, and no Effect.js. It follows the exact pattern of `shell.ts` (plain exports, no framework).

**Full file content:**

```typescript
export type ThemeId = "t3-dark" | "t3-light" | "t3-midnight";
export type ThemeSelection = ThemeId | "system";

export type ThemeColorTokens = {
  background: string;
  foreground: string;
  accent: string;
  sidebar: string;
  editor: string;
  terminal: string;
  statusBar: string;
};

export type ThemeDefinition = {
  id: ThemeId;
  label: string;
  colorScheme: "light" | "dark";
  tokens: ThemeColorTokens;
};

export const BUILT_IN_THEMES: readonly ThemeDefinition[] = [
  {
    id: "t3-light",
    label: "Light",
    colorScheme: "light",
    tokens: {
      background: "oklch(1.0 0 0)",
      foreground: "oklch(0.27 0 0)",
      accent: "oklch(0.488 0.217 264)",
      sidebar: "oklch(0.97 0 0)",
      editor: "oklch(1.0 0 0)",
      terminal: "oklch(0.98 0 0)",
      statusBar: "oklch(0.94 0 0)",
    },
  },
  {
    id: "t3-dark",
    label: "Dark",
    colorScheme: "dark",
    tokens: {
      background: "oklch(0.105 0 0)",
      foreground: "oklch(0.94 0 0)",
      accent: "oklch(0.588 0.217 264)",
      sidebar: "oklch(0.09 0 0)",
      editor: "oklch(0.085 0 0)",
      terminal: "oklch(0.08 0 0)",
      statusBar: "oklch(0.115 0 0)",
    },
  },
  {
    id: "t3-midnight",
    label: "Midnight",
    colorScheme: "dark",
    tokens: {
      background: "oklch(0.07 0.018 264)",
      foreground: "oklch(0.92 0.008 264)",
      accent: "oklch(0.65 0.24 264)",
      sidebar: "oklch(0.055 0.018 264)",
      editor: "oklch(0.05 0.015 264)",
      terminal: "oklch(0.04 0.01 264)",
      statusBar: "oklch(0.065 0.018 264)",
    },
  },
] as const;

export const DEFAULT_THEME_ID: ThemeId = "t3-dark";

export function getBuiltInTheme(id: ThemeId): ThemeDefinition {
  const found = BUILT_IN_THEMES.find((t) => t.id === id);
  if (!found) {
    throw new Error(`Unknown theme id: ${id}`);
  }
  return found;
}

export function isThemeId(value: string): value is ThemeId {
  return value === "t3-dark" || value === "t3-light" || value === "t3-midnight";
}

export function isThemeSelection(value: string): value is ThemeSelection {
  return value === "system" || isThemeId(value);
}

/**
 * Maps a legacy localStorage value ("light", "dark") to a ThemeSelection.
 * Returns null if the value is already a valid ThemeSelection (no migration needed).
 */
export function migrateLegacyThemeValue(raw: string): ThemeSelection | null {
  if (raw === "light") return "t3-light";
  if (raw === "dark") return "t3-dark";
  return null;
}
```

**Color token rationale:**
- `t3-light` tokens pull directly from what the existing `:root` CSS block renders at runtime. The `background` is white (`oklch(1.0 0 0)`), `foreground` is neutral-800 equivalent, `sidebar` is a slightly off-white.
- `t3-dark` tokens reflect what the existing `@variant dark` block renders: `background` is near `color-mix(in srgb, neutral-950 95%, white)` ≈ `oklch(0.105 0 0)`.
- `t3-midnight` tokens are exactly as specified in the requirements.
- The `accent` tokens use the actual `--primary` oklch values already in the CSS file: `oklch(0.488 0.217 264)` for light, `oklch(0.588 0.217 264)` for dark/midnight.

**Design decision flag:** The `tokens` object in `ThemeDefinition` stores CSS color strings. These are used only by `ThemeSelector` for color swatch display — they are NOT used to drive the actual CSS custom properties. The CSS is the source of truth for rendering. The tokens exist purely as a visual reference for the UI. If you want them to also drive the CSS directly (replacing the static CSS class mechanism), that is a larger scope change not required here.

