### Step 4: `apps/web/src/hooks/useTheme.ts` — Replace existing file entirely

This is the core of the change. The existing file is a clean, self-contained module-level store using `useSyncExternalStore`. The new version follows exactly the same pattern but handles `ThemeId | "system"` instead of `"light" | "dark" | "system"`.

**Full replacement content:**

```typescript
import { useCallback, useEffect, useSyncExternalStore } from "react";
import {
  type ThemeSelection,
  type ThemeId,
  isThemeSelection,
  migrateLegacyThemeValue,
  getBuiltInTheme,
} from "@t3tools/shared/theme";

// Re-export types that consumers may use
export type { ThemeSelection, ThemeId };

const STORAGE_KEY = "t3code:theme";
const MEDIA_QUERY = "(prefers-color-scheme: dark)";

type ThemeSnapshot = {
  selection: ThemeSelection;
  systemDark: boolean;
};

let listeners: Array<() => void> = [];
let lastSnapshot: ThemeSnapshot | null = null;

function emitChange() {
  for (const listener of listeners) listener();
}

function getSystemDark(): boolean {
  return window.matchMedia(MEDIA_QUERY).matches;
}

function getStored(): ThemeSelection {
  const raw = localStorage.getItem(STORAGE_KEY);
  if (!raw) return "system";

  // Migration: map old "light"/"dark" values to new ThemeIds
  const migrated = migrateLegacyThemeValue(raw);
  if (migrated) {
    // Write migrated value back so next read is clean
    localStorage.setItem(STORAGE_KEY, migrated);
    return migrated;
  }

  if (isThemeSelection(raw)) return raw;
  return "system";
}

function applyTheme(selection: ThemeSelection, suppressTransitions = false) {
  if (suppressTransitions) {
    document.documentElement.classList.add("no-transitions");
  }

  const isDark =
    selection === "t3-dark" ||
    selection === "t3-midnight" ||
    (selection === "system" && getSystemDark());

  const isMidnight = selection === "t3-midnight";

  document.documentElement.classList.toggle("dark", isDark);
  document.documentElement.classList.toggle("t3-midnight", isMidnight);

  if (suppressTransitions) {
    // Force reflow so no-transitions takes effect before removal
    // oxlint-disable-next-line no-unused-expressions
    document.documentElement.offsetHeight;
    requestAnimationFrame(() => {
      document.documentElement.classList.remove("no-transitions");
    });
  }
}

// Apply immediately on module load to prevent flash
applyTheme(getStored());

function getSnapshot(): ThemeSnapshot {
  const selection = getStored();
  const systemDark = selection === "system" ? getSystemDark() : false;

  if (
    lastSnapshot &&
    lastSnapshot.selection === selection &&
    lastSnapshot.systemDark === systemDark
  ) {
    return lastSnapshot;
  }

  lastSnapshot = { selection, systemDark };
  return lastSnapshot;
}

function subscribe(listener: () => void): () => void {
  listeners.push(listener);

  const mq = window.matchMedia(MEDIA_QUERY);
  const handleChange = () => {
    if (getStored() === "system") applyTheme("system", true);
    emitChange();
  };
  mq.addEventListener("change", handleChange);

  const handleStorage = (e: StorageEvent) => {
    if (e.key === STORAGE_KEY) {
      applyTheme(getStored(), true);
      emitChange();
    }
  };
  window.addEventListener("storage", handleStorage);

  return () => {
    listeners = listeners.filter((l) => l !== listener);
    mq.removeEventListener("change", handleChange);
    window.removeEventListener("storage", handleStorage);
  };
}

export function useTheme() {
  const snapshot = useSyncExternalStore(subscribe, getSnapshot);
  const selection = snapshot.selection;

  // resolvedTheme stays "light" | "dark" for full backwards compatibility
  // with DiffWorkerPoolProvider, ChatView, DiffPanel, ChatMarkdown
  const resolvedTheme: "light" | "dark" = (() => {
    if (selection === "system") return snapshot.systemDark ? "dark" : "light";
    const def = getBuiltInTheme(selection);
    return def.colorScheme;
  })();

  // theme stays as ThemeSelection for the settings page
  const theme: ThemeSelection = selection;

  const setTheme = useCallback((next: ThemeSelection) => {
    localStorage.setItem(STORAGE_KEY, next);
    applyTheme(next, true);
    emitChange();
  }, []);

  // Keep DOM in sync on mount/change
  useEffect(() => {
    applyTheme(selection);
  }, [selection]);

  return { theme, setTheme, resolvedTheme } as const;
}
```

**Key backward-compat points:**
- `resolvedTheme` remains `"light" | "dark"` — unchanged type, unchanged semantics.
- `theme` changes type from `"light" | "dark" | "system"` to `ThemeSelection` (i.e., `"t3-dark" | "t3-light" | "t3-midnight" | "system"`). The settings page is the only consumer of `theme` directly (other files only use `resolvedTheme`), and the settings page will be updated in Step 6.
- `setTheme` parameter type changes from `Theme` to `ThemeSelection`. Only the settings page (Step 6) calls `setTheme`.
- Migration runs on `getStored()` every time, writing back immediately, so old users are upgraded transparently on first run.

**Design decision flag:** `getStored()` calls `migrateLegacyThemeValue` and writes back to `localStorage`. This means the migration is not a one-time event with a version guard — it runs every call until the value is valid. This is safe because `migrateLegacyThemeValue` only triggers on the exact strings `"light"` and `"dark"`, which will never be written by the new code. There is no need for a separate migration version key.

**Design decision flag:** `getBuiltInTheme(selection)` is called inside the `useTheme` hook synchronously in the render. This will throw if somehow an unknown ThemeId ends up in storage (e.g., a future theme that was removed). The `getStored()` guard with `isThemeSelection` protects against this — if the stored value is not a known ThemeSelection, it falls back to `"system"`. So `getBuiltInTheme` will only be called with a valid current `ThemeId`. This is safe.

