## Step 4 — `apps/web/src/hooks/useTheme.ts` (full rewrite)

Keeps the same `useSyncExternalStore` module-level store pattern. Key changes:
- `ThemeSelection = ThemeId | "system"` replaces `Theme = "light" | "dark" | "system"`
- `applyTheme()` toggles both `.dark` and `.t3-midnight` classes
- `getStored()` runs migration (old `"light"` → `"t3-light"`, old `"dark"` → `"t3-dark"`) and writes back immediately
- Return shape: `{ theme: ThemeSelection, setTheme, resolvedTheme: "light" | "dark" }` — `resolvedTheme` type is **unchanged** for full backwards compat with `DiffWorkerPoolProvider`

```typescript
import { useCallback, useEffect, useSyncExternalStore } from "react";
import {
  type ThemeSelection,
  isThemeSelection,
  migrateLegacyThemeValue,
  getBuiltInTheme,
} from "@t3tools/shared/theme";

export type { ThemeSelection };

const STORAGE_KEY = "t3code:theme";
const MEDIA_QUERY = "(prefers-color-scheme: dark)";

type ThemeSnapshot = { selection: ThemeSelection; systemDark: boolean };

let listeners: Array<() => void> = [];
let lastSnapshot: ThemeSnapshot | null = null;

function emitChange() {
  for (const listener of listeners) listener();
}

function getSystemDark(): boolean {
  return window.matchMedia(MEDIA_QUERY).matches;
}

function getStored(): ThemeSelection {
  const raw = localStorage.getItem(STORAGE_KEY);
  if (!raw) return "system";
  const migrated = migrateLegacyThemeValue(raw);
  if (migrated) {
    localStorage.setItem(STORAGE_KEY, migrated);
    return migrated;
  }
  if (isThemeSelection(raw)) return raw;
  return "system";
}

function applyTheme(selection: ThemeSelection, suppressTransitions = false) {
  if (suppressTransitions) {
    document.documentElement.classList.add("no-transitions");
  }
  const isDark =
    selection === "t3-dark" ||
    selection === "t3-midnight" ||
    (selection === "system" && getSystemDark());
  document.documentElement.classList.toggle("dark", isDark);
  document.documentElement.classList.toggle("t3-midnight", selection === "t3-midnight");
  if (suppressTransitions) {
    // oxlint-disable-next-line no-unused-expressions
    document.documentElement.offsetHeight;
    requestAnimationFrame(() => {
      document.documentElement.classList.remove("no-transitions");
    });
  }
}

applyTheme(getStored()); // prevent flash on module load

function getSnapshot(): ThemeSnapshot {
  const selection = getStored();
  const systemDark = selection === "system" ? getSystemDark() : false;
  if (lastSnapshot?.selection === selection && lastSnapshot.systemDark === systemDark) {
    return lastSnapshot;
  }
  lastSnapshot = { selection, systemDark };
  return lastSnapshot;
}

function subscribe(listener: () => void): () => void {
  listeners.push(listener);
  const mq = window.matchMedia(MEDIA_QUERY);
  const handleChange = () => {
    if (getStored() === "system") applyTheme("system", true);
    emitChange();
  };
  mq.addEventListener("change", handleChange);
  const handleStorage = (e: StorageEvent) => {
    if (e.key === STORAGE_KEY) {
      applyTheme(getStored(), true);
      emitChange();
    }
  };
  window.addEventListener("storage", handleStorage);
  return () => {
    listeners = listeners.filter((l) => l !== listener);
    mq.removeEventListener("change", handleChange);
    window.removeEventListener("storage", handleStorage);
  };
}

export function useTheme() {
  const snapshot = useSyncExternalStore(subscribe, getSnapshot);
  const selection = snapshot.selection;

  const resolvedTheme: "light" | "dark" = (() => {
    if (selection === "system") return snapshot.systemDark ? "dark" : "light";
    return getBuiltInTheme(selection).colorScheme;
  })();

  const setTheme = useCallback((next: ThemeSelection) => {
    localStorage.setItem(STORAGE_KEY, next);
    applyTheme(next, true);
    emitChange();
  }, []);

  useEffect(() => {
    applyTheme(selection);
  }, [selection]);

  return { theme: selection, setTheme, resolvedTheme } as const;
}
```

**`resolvedTheme` compatibility table:**

| stored selection | resolvedTheme | `<html>` classes |
|---|---|---|
| `"system"` (OS=light) | `"light"` | — |
| `"system"` (OS=dark) | `"dark"` | `.dark` |
| `"t3-light"` | `"light"` | — |
| `"t3-dark"` | `"dark"` | `.dark` |
| `"t3-midnight"` | `"dark"` | `.dark .t3-midnight` |
| (old) `"light"` | → migrated to `"t3-light"` → `"light"` | — |
| (old) `"dark"` | → migrated to `"t3-dark"` → `"dark"` | `.dark` |

---

## Step 5 — `apps/web/src/components/ThemeProvider.tsx` (new file)

```typescript
import { type ReactNode } from "react";
import { useTheme } from "../hooks/useTheme";

interface ThemeProviderProps {
  children: ReactNode;
}

/**
 * ThemeProvider ensures the theme is applied to the document root on mount
 * and keeps it in sync throughout the app lifecycle.
 */
export function ThemeProvider({ children }: ThemeProviderProps) {
  useTheme(); // subscribes to theme store; useEffect inside keeps DOM in sync
  return <>{children}</>;
}
```

---

## Step 6 — `apps/web/src/components/ThemeSelector.tsx` (new file)

```typescript
