            )}
            onClick={() => setTheme(option.value)}
          >
            <span className="flex flex-col gap-1.5">
              <span className="flex items-center gap-2">
                {tokens ? (
                  <span
                    className="inline-flex h-3.5 w-10 shrink-0 overflow-hidden rounded-sm border border-black/10"
                    aria-hidden="true"
                  >
                    <span className="flex-1" style={{ background: tokens.background }} />
                    <span className="w-2 shrink-0" style={{ background: tokens.sidebar }} />
                    <span className="w-2 shrink-0" style={{ background: tokens.accent }} />
                  </span>
                ) : null}
                <span className="text-sm font-medium">{option.label}</span>
              </span>
              <span className="text-xs">{option.description}</span>
            </span>
            {selected ? (
              <span className="rounded bg-primary/14 px-1.5 py-0.5 text-[10px] font-medium uppercase tracking-wide text-primary">
                Selected
              </span>
            ) : null}
          </button>
        );
      })}
    </div>
  );
}
