import { BUILT_IN_THEMES, type ThemeSelection } from "@t3tools/shared/theme";
import { useTheme } from "../hooks/useTheme";
import { cn } from "~/lib/utils";

const THEME_SELECTOR_OPTIONS: Array<{
  value: ThemeSelection;
  label: string;
  description: string;
}> = [
  { value: "system", label: "System", description: "Match your OS appearance setting." },
  { value: "t3-light", label: "Light", description: "Always use the light theme." },
  { value: "t3-dark", label: "Dark", description: "Always use the dark theme." },
  { value: "t3-midnight", label: "Midnight", description: "Deep blue-black dark variant." },
];

interface ThemeSelectorProps {
  className?: string;
}

export function ThemeSelector({ className }: ThemeSelectorProps) {
  const { theme, setTheme } = useTheme();

  return (
    <div className={cn("space-y-2", className)} role="radiogroup" aria-label="Theme preference">
      {THEME_SELECTOR_OPTIONS.map((option) => {
        const selected = theme === option.value;
        const tokens =
          option.value !== "system"
            ? BUILT_IN_THEMES.find((t) => t.id === option.value)?.tokens
            : null;

        return (
          <button
            key={option.value}
            type="button"
            role="radio"
            aria-checked={selected}
            className={cn(
              "flex w-full items-start justify-between rounded-lg border px-3 py-2 text-left transition-colors",
              selected
                ? "border-primary/60 bg-primary/8 text-foreground"
                : "border-border bg-background text-muted-foreground hover:bg-accent",
            )}
            onClick={() => setTheme(option.value)}
          >
            <span className="flex flex-col gap-1.5">
              <span className="flex items-center gap-2">
                {tokens ? (
                  <span
                    className="inline-flex h-3.5 w-10 shrink-0 overflow-hidden rounded-sm border border-black/10"
                    aria-hidden="true"
                  >
                    <span className="flex-1" style={{ background: tokens.background }} />
                    <span className="w-2 shrink-0" style={{ background: tokens.sidebar }} />
                    <span className="w-2 shrink-0" style={{ background: tokens.accent }} />
                  </span>
                ) : null}
                <span className="text-sm font-medium">{option.label}</span>
              </span>
              <span className="text-xs">{option.description}</span>
            </span>
            {selected ? (
              <span className="rounded bg-primary/14 px-1.5 py-0.5 text-[10px] font-medium uppercase tracking-wide text-primary">
                Selected
              </span>
            ) : null}
          </button>
        );
      })}
    </div>
  );
}
```

