280	                </label>
281	
282	                <div className="flex items-center justify-between gap-2 text-xs text-muted-foreground">
283	                  <p>
284	                    Binary source:{" "}
285	                    <span className="font-medium text-foreground">{codexBinaryPath || "PATH"}</span>
286	                  </p>
287	                  <Button
288	                    size="xs"
289	                    variant="outline"
290	                    onClick={() =>
291	                      updateSettings({
