/** Named theme identifiers for the T3 Code built-in themes. */
export type ThemeId = "t3-light" | "t3-dark" | "t3-midnight";

/** The set of valid theme selections, including system preference. */
export type ThemeSelection = ThemeId | "system";

/** Colour tokens used for UI preview swatches. Not applied directly as CSS variables. */
export interface ThemeColorTokens {
  background: string;
  foreground: string;
  accent: string;
  sidebar: string;
  editor: string;
  terminal: string;
  statusBar: string;
}

export interface ThemeDefinition {
  id: ThemeId;
  label: string;
  description: string;
  /** Whether this theme applies the `.dark` class to `<html>`. */
  isDark: boolean;
  /** Preview colour tokens for swatches; not applied as CSS variables. */
  colors: ThemeColorTokens;
}

export const BUILT_IN_THEMES: ReadonlyArray<ThemeDefinition> = [
  {
    id: "t3-light",
    label: "Light",
    description: "Always use the light theme.",
    isDark: false,
    colors: {
      background: "#ffffff",
      foreground: "#262626",
      accent: "#6d28d9",
      sidebar: "#f5f5f5",
      editor: "#ffffff",
      terminal: "#fafafa",
      statusBar: "#e5e5e5",
    },
  },
  {
    id: "t3-dark",
    label: "Dark",
    description: "Always use the dark theme.",
    isDark: true,
    colors: {
      background: "#0a0a0f",
      foreground: "#f5f5f5",
      accent: "#7c3aed",
      sidebar: "#111118",
      editor: "#0d0d14",
      terminal: "#0a0a0f",
      statusBar: "#111118",
    },
  },
  {
    id: "t3-midnight",
    label: "Midnight",
    description: "Deep blue-black theme with indigo accents.",
    isDark: true,
    colors: {
      background: "#080c18",
      foreground: "#e2e8f4",
      accent: "#6366f1",
      sidebar: "#0d1220",
      editor: "#0a0e1c",
      terminal: "#080c18",
      statusBar: "#0d1220",
    },
  },
] as const;

/** Look up a built-in theme by ID. Throws if the ID is unknown. */
export function getBuiltInTheme(id: ThemeId): ThemeDefinition {
  const theme = BUILT_IN_THEMES.find((t) => t.id === id);
  if (!theme) throw new Error(`Unknown built-in theme: ${id}`);
  return theme;
}

/** Type guard: is this string a valid ThemeId? */
export function isThemeId(value: string): value is ThemeId {
  return value === "t3-light" || value === "t3-dark" || value === "t3-midnight";
}

/** Type guard: is this string a valid ThemeSelection? */
export function isThemeSelection(value: string): value is ThemeSelection {
  return value === "system" || isThemeId(value);
}

/**
 * Migrate legacy localStorage values to the new named theme IDs.
 * `"light"` → `"t3-light"`, `"dark"` → `"t3-dark"`, anything else → `"system"`.
 */
export function migrateLegacyThemeValue(raw: string): ThemeSelection {
  if (isThemeSelection(raw)) return raw;
  if (raw === "light") return "t3-light";
  if (raw === "dark") return "t3-dark";
  return "system";
}

