import { type ReactNode } from "react";
import { useTheme } from "../hooks/useTheme";

interface ThemeProviderProps {
  children: ReactNode;
}

/**
 * ThemeProvider mounts the useTheme hook at a stable boundary near the root
 * of the React tree. This ensures the module-level store is subscribed and
 * the DOM is kept in sync even before any consumer renders.
 */
export function ThemeProvider({ children }: ThemeProviderProps) {
  // Calling useTheme here ensures the subscription is active and the DOM is
  // kept in sync whenever the theme changes or the system preference fires.
  useTheme();
  return <>{children}</>;
}

