import { BUILT_IN_THEMES, type ThemeColorTokens, type ThemeSelection } from "@t3tools/shared/theme";
import { useTheme } from "../hooks/useTheme";

const SYSTEM_OPTION = {
  value: "system" as const,
  label: "System",
  description: "Match your OS appearance setting.",
  colors: null,
};

/**
 * Theme selector rendered as an accessible radio group. Each named theme
 * includes a colour swatch built from its preview tokens.
 */
export function ThemeSelector() {
  const { theme, setTheme } = useTheme();

  const options: Array<{
    value: ThemeSelection;
    label: string;
    description: string;
    colors: ThemeColorTokens | null;
  }> = [
    SYSTEM_OPTION,
    ...BUILT_IN_THEMES.map((t) => ({
      value: t.id,
      label: t.label,
      description: t.description,
      colors: t.colors,
    })),
  ];

  return (
    <div className="space-y-2" role="radiogroup" aria-label="Theme preference">
      {options.map((option) => {
        const selected = theme === option.value;
        return (
          <button
            key={option.value}
            type="button"
            role="radio"
            aria-checked={selected}
            className={`flex w-full items-start justify-between rounded-lg border px-3 py-2 text-left transition-colors ${
              selected
                ? "border-primary/60 bg-primary/8 text-foreground"
                : "border-border bg-background text-muted-foreground hover:bg-accent"
            }`}
            onClick={() => setTheme(option.value)}
          >
            <span className="flex flex-col gap-0.5">
              <span className="flex items-center gap-2">
                <span className="text-sm font-medium">{option.label}</span>
                {option.colors ? (
                  <ThemeSwatch colors={option.colors} />
                ) : (
                  <SystemSwatch />
                )}
              </span>
              <span className="text-xs">{option.description}</span>
            </span>
            {selected ? (
              <span className="shrink-0 rounded bg-primary/14 px-1.5 py-0.5 text-[10px] font-medium uppercase tracking-wide text-primary">
                Selected
              </span>
            ) : null}
          </button>
        );
      })}
    </div>
  );
}

function ThemeSwatch({ colors }: { colors: ThemeColorTokens }) {
  return (
    <span
      className="inline-flex h-4 w-10 overflow-hidden rounded-sm border border-border/50"
      aria-hidden="true"
    >
      <span className="w-3 shrink-0" style={{ background: colors.sidebar }} />
      <span className="flex-1" style={{ background: colors.editor }} />
      <span className="w-1 shrink-0" style={{ background: colors.accent }} />
    </span>
  );
}

/** Split swatch showing light on the left and dark on the right for the system option. */
function SystemSwatch() {
  return (
    <span
      className="inline-flex h-4 w-10 overflow-hidden rounded-sm border border-border/50"
      aria-hidden="true"
    >
      <span className="flex-1" style={{ background: "#ffffff" }} />
      <span className="flex-1" style={{ background: "#0a0a0f" }} />
    </span>
  );
}

